import {useEffect} from 'react';

function getContent(blogid){
	console.log(blogid);
	return 0;
}

function Blogpage(props){
	useEffect(() => {
		getContent(props.blogid);
	}, []);
	
	return (
		<div style={{color: 'black'}}>
			{props.blogid}
		</div>
	)
}

export default Blogpage;